int knapsack(int capacity, std::vector<int> const& weights, std::vector<int> const& values)
{
  if (weights.empty() || values.empty()) {
    return 0;
  }
  if (capacity <= 0) {
    return 0;
  }
  std::vector<std::vector<int>> table;
  table.reserve(weights.size() + 1);
  std::vector<int> row;
  row.reserve(capacity + 1);
  table.push_back(std::move(row));
  for (int i = 0; i <= capacity; ++i) {
    row.push_back(i);
    table.push_back(std::move(row));
  }
  for (int i = 1; i < weights.size() + 1; ++i) {
    for (int j = 1; j < capacity + 1; ++j) {
      if (weights[i - 1] > j) {
        table[i][j] = table[i - 1][j];
      } else {
        table[i][j] = std::max(values[i - 1] + table[i - 1][j - weights[i - 1]], table[i - 1][j]);
      }
    }
  }
  return table[weights.size()][capacity];
}

